Here's a comprehensive implementation of a worker pool pattern in Go with modern best practices:

## Basic Worker Pool Implementation

```go
package main

import (
    "context"
    "fmt"
    "sync"
    "time"
)

// Task represents a unit of work
type Task struct {
    ID   int
    Data interface{}
}

// Result represents the processed task output
type Result struct {
    TaskID int
    Output interface{}
    Err    error
}

// WorkerPool manages a pool of worker goroutines
type WorkerPool struct {
    numWorkers int
    tasks      chan Task
    results    chan Result
    wg         sync.WaitGroup
    ctx        context.Context
    cancel     context.CancelFunc
}

// NewWorkerPool creates a new worker pool
func NewWorkerPool(numWorkers, bufferSize int) *WorkerPool {
    ctx, cancel := context.WithCancel(context.Background())

    return &WorkerPool{
        numWorkers: numWorkers,
        tasks:      make(chan Task, bufferSize),
        results:    make(chan Result, bufferSize),
        ctx:        ctx,
        cancel:     cancel,
    }
}

// Start initializes and starts the worker pool
func (wp *WorkerPool) Start(processor func(Task) (interface{}, error)) {
    wp.wg.Add(wp.numWorkers)

    for i := 0; i < wp.numWorkers; i++ {
        go wp.worker(i, processor)
    }
}

// worker processes tasks from the channel
func (wp *WorkerPool) worker(id int, processor func(Task) (interface{}, error)) {
    defer wp.wg.Done()

    for {
        select {
        case <-wp.ctx.Done():
            return
        case task, ok := <-wp.tasks:
            if !ok {
                return
            }

            // Process the task
            output, err := processor(task)

            // Send result
            select {
            case <-wp.ctx.Done():
                return
            case wp.results <- Result{
                TaskID: task.ID,
                Output: output,
                Err:    err,
            }:
            }
        }
    }
}

// Submit adds a task to the pool
func (wp *WorkerPool) Submit(task Task) error {
    select {
    case <-wp.ctx.Done():
        return fmt.Errorf("worker pool stopped")
    case wp.tasks <- task:
        return nil
    }
}

// Results returns a channel to receive processed results
func (wp *WorkerPool) Results() <-chan Result {
    return wp.results
}

// Stop gracefully shuts down the worker pool
func (wp *WorkerPool) Stop() {
    wp.cancel()      // Signal all workers to stop
    close(wp.tasks)  // Close tasks channel
    wp.wg.Wait()     // Wait for all workers to finish
    close(wp.results) // Close results channel
}

// Example usage
func main() {
    // Create a worker pool with 5 workers and buffer size 100
    pool := NewWorkerPool(5, 100)

    // Define task processor
    processor := func(task Task) (interface{}, error) {
        // Simulate processing time
        time.Sleep(100 * time.Millisecond)

        // Example processing: square the ID
        if data, ok := task.Data.(int); ok {
            return data * data, nil
        }
        return nil, fmt.Errorf("invalid data type")
    }

    // Start the worker pool
    pool.Start(processor)

    // Submit tasks in a separate goroutine
    go func() {
        for i := 0; i < 20; i++ {
            task := Task{
                ID:   i,
                Data: i,
            }
            if err := pool.Submit(task); err != nil {
                fmt.Printf("Failed to submit task %d: %v\n", i, err)
            }
        }
    }()

    // Collect results
    go func() {
        for result := range pool.Results() {
            if result.Err != nil {
                fmt.Printf("Task %d failed: %v\n", result.TaskID, result.Err)
            } else {
                fmt.Printf("Task %d result: %v\n", result.TaskID, result.Output)
            }
        }
    }()

    // Wait for processing to complete
    time.Sleep(2 * time.Second)
    pool.Stop()
}
